content:
Ajax 和 JSON 是现代 Web 开发中最常用的数据交互技术。Ajax 用于在不刷新页面的情况下与服务器通信，JSON 是轻量级的数据交换格式。本文将详细介绍它们的使用方法。


1. Ajax 详解1.1 什么是 AjaxAjax（Asynchronous JavaScript and XML）是一种创建快速动态网页的技术。通过在后台与服务器进行少量数据交换，Ajax 可以使网页实现异步更新，无需重新加载整个页面。
1.2 原生 XMLHttpRequest// GET 请求const xhr = new XMLHttpRequest();xhr.open(&#x27;GET&#x27;, &#x27;https://api.example.com/users&#x27;, true);xhr.onload = () =&gt; &#123;    if (xhr.status === 200) &#123;        const users = JSON.parse(xhr.responseText);        console.log(users);    &#125; else &#123;        console.error(&#x27;请求失败:&#x27;, xhr.status);    &#125;&#125;;xhr.onerror = () =&gt; &#123;    console.error(&#x27;网络错误&#x27;);&#125;;xhr.send();// POST 请求const xhrPost = new XMLHttpRequest();xhrPost.open(&#x27;POST&#x27;, &#x27;https://api.example.com/users&#x27;, true);xhrPost.setRequestHeader(&#x27;Content-Type&#x27;, &#x27;application/json&#x27;);xhrPost.onload = () =&gt; &#123;    if (xhrPost.status === 201) &#123;        const newUser = JSON.parse(xhrPost.responseText);        console.log(&#x27;创建成功:&#x27;, newUser);    &#125;&#125;;xhrPost.send(JSON.stringify(&#123;    name: &#x27;张三&#x27;,    email: &#x27;zhangsan@example.com&#x27;&#125;));

1.3 Fetch API// GET 请求async function getUsers() &#123;    try &#123;        const response = await fetch(&#x27;https://api.example.com/users&#x27;);                if (!response.ok) &#123;            throw new Error(`HTTP error! status: $&#123;response.status&#125;`);        &#125;                const data = await response.json();        return data;    &#125; catch (error) &#123;        console.error(&#x27;请求失败:&#x27;, error);    &#125;&#125;// POST 请求async function createUser(userData) &#123;    try &#123;        const response = await fetch(&#x27;https://api.example.com/users&#x27;, &#123;            method: &#x27;POST&#x27;,            headers: &#123;                &#x27;Content-Type&#x27;: &#x27;application/json&#x27;,                &#x27;Authorization&#x27;: &#x27;Bearer token123&#x27;            &#125;,            body: JSON.stringify(userData)        &#125;);                if (!response.ok) &#123;            throw new Error(`HTTP error! status: $&#123;response.status&#125;`);        &#125;                return await response.json();    &#125; catch (error) &#123;        console.error(&#x27;创建失败:&#x27;, error);    &#125;&#125;// PUT 请求（更新）async function updateUser(id, userData) &#123;    const response = await fetch(`https://api.example.com/users/$&#123;id&#125;`, &#123;        method: &#x27;PUT&#x27;,        headers: &#123;            &#x27;Content-Type&#x27;: &#x27;application/json&#x27;        &#125;,        body: JSON.stringify(userData)    &#125;);    return await response.json();&#125;// DELETE 请求async function deleteUser(id) &#123;    const response = await fetch(`https://api.example.com/users/$&#123;id&#125;`, &#123;        method: &#x27;DELETE&#x27;    &#125;);    return response.ok;&#125;

1.4 请求超时处理function fetchWithTimeout(url, options = &#123;&#125;, timeout = 5000) &#123;    const controller = new AbortController();    const signal = controller.signal;        const timeoutId = setTimeout(() =&gt; &#123;        controller.abort();    &#125;, timeout);        return fetch(url, &#123;        ...options,        signal    &#125;)    .finally(() =&gt; &#123;        clearTimeout(timeoutId);    &#125;);&#125;// 使用fetchWithTimeout(&#x27;https://api.example.com/users&#x27;, &#123; method: &#x27;GET&#x27; &#125;, 3000)    .then(response =&gt; response.json())    .catch(error =&gt; &#123;        if (error.name === &#x27;AbortError&#x27;) &#123;            console.log(&#x27;请求超时&#x27;);        &#125; else &#123;            console.error(&#x27;请求失败:&#x27;, error);        &#125;    &#125;);

1.5 进度监控function uploadWithProgress(url, file, onProgress) &#123;    return new Promise((resolve, reject) =&gt; &#123;        const xhr = new XMLHttpRequest();                xhr.upload.onprogress = (event) =&gt; &#123;            if (event.lengthComputable) &#123;                const percent = Math.round((event.loaded / event.total) * 100);                onProgress(percent);            &#125;        &#125;;                xhr.onload = () =&gt; &#123;            if (xhr.status === 200) &#123;                resolve(JSON.parse(xhr.responseText));            &#125; else &#123;                reject(new Error(&#x27;上传失败&#x27;));            &#125;        &#125;;                xhr.onerror = () =&gt; reject(new Error(&#x27;网络错误&#x27;));                xhr.open(&#x27;POST&#x27;, url);                const formData = new FormData();        formData.append(&#x27;file&#x27;, file);                xhr.send(formData);    &#125;);&#125;// 使用const fileInput = document.querySelector(&#x27;input[type=&quot;file&quot;]&#x27;);fileInput.addEventListener(&#x27;change&#x27;, (e) =&gt; &#123;    const file = e.target.files[0];        uploadWithProgress(&#x27;/api/upload&#x27;, file, (percent) =&gt; &#123;        console.log(`上传进度: $&#123;percent&#125;%`);    &#125;)    .then(result =&gt; console.log(&#x27;上传成功:&#x27;, result))    .catch(error =&gt; console.error(&#x27;上传失败:&#x27;, error));&#125;);

2. JSON 详解2.1 什么是 JSONJSON（JavaScript Object Notation）是一种轻量级的数据交换格式。它基于 JavaScript 语法，但独立于编程语言。JSON 易于人阅读和编写，也易于机器解析和生成。
2.2 JSON 语法规则&#123;    &quot;name&quot;: &quot;张三&quot;,    &quot;age&quot;: 25,    &quot;isStudent&quot;: false,    &quot;scores&quot;: [85, 90, 78],    &quot;address&quot;: &#123;        &quot;city&quot;: &quot;北京&quot;,        &quot;district&quot;: &quot;朝阳区&quot;    &#125;,    &quot;friends&quot;: [        &#123;            &quot;name&quot;: &quot;李四&quot;,            &quot;age&quot;: 26        &#125;    ],    &quot;email&quot;: null&#125;

2.3 JSON 操作// 解析 JSON 字符串const jsonString = &#x27;&#123;&quot;name&quot;: &quot;张三&quot;, &quot;age&quot;: 25&#125;&#x27;;const obj = JSON.parse(jsonString);console.log(obj.name); // 张三// 对象转 JSON 字符串const user = &#123; name: &#x27;李四&#x27;, age: 30 &#125;;const jsonStr = JSON.stringify(user);console.log(jsonStr); // &#123;&quot;name&quot;:&quot;李四&quot;,&quot;age&quot;:30&#125;// 格式化输出const prettyJson = JSON.stringify(user, null, 4);console.log(prettyJson);/*&#123;    &quot;name&quot;: &quot;李四&quot;,    &quot;age&quot;: 30&#125;*/// 过滤字段const userFiltered = JSON.stringify(user, [&#x27;name&#x27;], 2);console.log(userFiltered);/*&#123;  &quot;name&quot;: &quot;李四&quot;&#125;*/

2.4 深拷贝// 使用 JSON 进行深拷贝const original = &#123;     name: &#x27;张三&#x27;,    address: &#123; city: &#x27;北京&#x27; &#125;&#125;;const copy = JSON.parse(JSON.stringify(original));copy.address.city = &#x27;上海&#x27;;console.log(original.address.city); // 北京（原始对象不变）console.log(copy.address.city);     // 上海

2.5 JSON Schema 验证// 简单的 JSON 验证function validateJSON(data, schema) &#123;    const errors = [];        for (const [key, rules] of Object.entries(schema)) &#123;        const value = data[key];                // 必填检查        if (rules.required &amp;&amp; (value === undefined || value === null)) &#123;            errors.push(`$&#123;key&#125; 是必填字段`);            continue;        &#125;                // 类型检查        if (rules.type &amp;&amp; typeof value !== rules.type) &#123;            errors.push(`$&#123;key&#125; 应该是 $&#123;rules.type&#125; 类型`);        &#125;                // 范围检查        if (rules.min !== undefined &amp;&amp; value &lt; rules.min) &#123;            errors.push(`$&#123;key&#125; 不能小于 $&#123;rules.min&#125;`);        &#125;                if (rules.max !== undefined &amp;&amp; value &gt; rules.max) &#123;            errors.push(`$&#123;key&#125; 不能大于 $&#123;rules.max&#125;`);        &#125;                // 枚举检查        if (rules.enum &amp;&amp; !rules.enum.includes(value)) &#123;            errors.push(`$&#123;key&#125; 必须是 $&#123;rules.enum.join(&#x27;、&#x27;)&#125; 之一`);        &#125;    &#125;        return &#123;        valid: errors.length === 0,        errors    &#125;;&#125;// 使用const schema = &#123;    name: &#123; required: true, type: &#x27;string&#x27; &#125;,    age: &#123; type: &#x27;number&#x27;, min: 0, max: 150 &#125;,    gender: &#123; enum: [&#x27;男&#x27;, &#x27;女&#x27;, &#x27;其他&#x27;] &#125;&#125;;const data = &#123; name: &#x27;张三&#x27;, age: -1 &#125;;const result = validateJSON(data, schema);console.log(result);// &#123; valid: false, errors: [&#x27;age 不能小于 0&#x27;] &#125;

3. 实战技巧3.1 封装请求工具class HttpClient &#123;    constructor(baseURL = &#x27;&#x27;) &#123;        this.baseURL = baseURL;        this.defaultHeaders = &#123;            &#x27;Content-Type&#x27;: &#x27;application/json&#x27;        &#125;;    &#125;    async request(endpoint, options = &#123;&#125;) &#123;        const url = this.baseURL + endpoint;                const config = &#123;            ...options,            headers: &#123;                ...this.defaultHeaders,                ...options.headers            &#125;        &#125;;                try &#123;            const response = await fetch(url, config);                        if (!response.ok) &#123;                throw new Error(`请求失败: $&#123;response.status&#125;`);            &#125;                        const contentType = response.headers.get(&#x27;content-type&#x27;);            if (contentType &amp;&amp; contentType.includes(&#x27;application/json&#x27;)) &#123;                return await response.json();            &#125;                        return await response.text();        &#125; catch (error) &#123;            console.error(&#x27;请求错误:&#x27;, error);            throw error;        &#125;    &#125;    get(endpoint, params = &#123;&#125;) &#123;        const queryString = new URLSearchParams(params).toString();        const url = queryString ? `$&#123;endpoint&#125;?$&#123;queryString&#125;` : endpoint;        return this.request(url, &#123; method: &#x27;GET&#x27; &#125;);    &#125;    post(endpoint, data) &#123;        return this.request(endpoint, &#123;            method: &#x27;POST&#x27;,            body: JSON.stringify(data)        &#125;);    &#125;    put(endpoint, data) &#123;        return this.request(endpoint, &#123;            method: &#x27;PUT&#x27;,            body: JSON.stringify(data)        &#125;);    &#125;    delete(endpoint) &#123;        return this.request(endpoint, &#123; method: &#x27;DELETE&#x27; &#125;);    &#125;&#125;// 使用const api = new HttpClient(&#x27;https://api.example.com&#x27;);// 获取用户列表const users = await api.get(&#x27;/users&#x27;);// 创建用户const newUser = await api.post(&#x27;/users&#x27;, &#123;    name: &#x27;王五&#x27;,    email: &#x27;wangwu@example.com&#x27;&#125;);// 更新用户const updatedUser = await api.put(&#x27;/users/1&#x27;, &#123;    name: &#x27;王五（已修改）&#x27;&#125;);// 删除用户await api.delete(&#x27;/users/1&#x27;);

3.2 请求缓存class RequestCache &#123;    constructor(maxAge = 60000) &#123; // 默认 1 分钟        this.cache = new Map();        this.maxAge = maxAge;    &#125;    get(key) &#123;        const item = this.cache.get(key);        if (!item) return null;                if (Date.now() - item.timestamp &gt; this.maxAge) &#123;            this.cache.delete(key);            return null;        &#125;                return item.data;    &#125;    set(key, data) &#123;        this.cache.set(key, &#123;            data,            timestamp: Date.now()        &#125;);    &#125;    clear() &#123;        this.cache.clear();    &#125;&#125;const cache = new RequestCache(30000); // 30 秒缓存async function fetchWithCache(url) &#123;    const cached = cache.get(url);    if (cached) &#123;        console.log(&#x27;使用缓存&#x27;);        return cached;    &#125;        const response = await fetch(url);    const data = await response.json();        cache.set(url, data);    return data;&#125;

3.3 分页加载class PaginatedLoader &#123;    constructor(fetchFn, pageSize = 10) &#123;        this.fetchFn = fetchFn;        this.pageSize = pageSize;        this.page = 1;        this.hasMore = true;        this.loading = false;        this.data = [];    &#125;    async loadMore() &#123;        if (this.loading || !this.hasMore) return;                this.loading = true;                try &#123;            const result = await this.fetchFn(this.page, this.pageSize);                        this.data = [...this.data, ...result.items];            this.hasMore = result.hasMore;            this.page++;                        return result.items;        &#125; finally &#123;            this.loading = false;        &#125;    &#125;    reset() &#123;        this.page = 1;        this.hasMore = true;        this.loading = false;        this.data = [];    &#125;&#125;// 使用const loader = new PaginatedLoader(async (page, size) =&gt; &#123;    const response = await fetch(`/api/users?page=$&#123;page&#125;&amp;size=$&#123;size&#125;`);    return await response.json();&#125;);// 加载更多const newItems = await loader.loadMore();

3.4 数据转换// JSON 转 FormDatafunction jsonToFormData(json) &#123;    const formData = new FormData();        function appendFormData(data, prefix = &#x27;&#x27;) &#123;        for (const [key, value] of Object.entries(data)) &#123;            const formKey = prefix ? `$&#123;prefix&#125;[$&#123;key&#125;]` : key;                        if (value instanceof Object &amp;&amp; !(value instanceof File)) &#123;                appendFormData(value, formKey);            &#125; else &#123;                formData.append(formKey, value);            &#125;        &#125;    &#125;        appendFormData(json);    return formData;&#125;// FormData 转 JSONfunction formDataToJson(formData) &#123;    const json = &#123;&#125;;        for (const [key, value] of formData.entries()) &#123;        const keys = key.replace(/\]/g, &#x27;&#x27;).split(&#x27;[&#x27;);        let current = json;                for (let i = 0; i &lt; keys.length; i++) &#123;            const k = keys[i];                        if (i === keys.length - 1) &#123;                current[k] = value;            &#125; else &#123;                current[k] = current[k] || &#123;&#125;;                current = current[k];            &#125;        &#125;    &#125;        return json;&#125;// CSV 转 JSONfunction csvToJson(csv) &#123;    const lines = csv.split(&#x27;\n&#x27;).filter(line =&gt; line.trim());    const headers = lines[0].split(&#x27;,&#x27;).map(h =&gt; h.trim());        return lines.slice(1).map(line =&gt; &#123;        const values = line.split(&#x27;,&#x27;);        const obj = &#123;&#125;;                headers.forEach((header, index) =&gt; &#123;            obj[header] = values[index]?.trim();        &#125;);                return obj;    &#125;);&#125;// JSON 转 CSVfunction jsonToCsv(data) &#123;    if (!data.length) return &#x27;&#x27;;        const headers = Object.keys(data[0]);    const csvLines = [headers.join(&#x27;,&#x27;)];        data.forEach(item =&gt; &#123;        const values = headers.map(header =&gt; &#123;            const value = item[header] ?? &#x27;&#x27;;            return value.includes(&#x27;,&#x27;) ? `&quot;$&#123;value&#125;&quot;` : value;        &#125;);        csvLines.push(values.join(&#x27;,&#x27;));    &#125;);        return csvLines.join(&#x27;\n&#x27;);&#125;

3.5 大数据量处理// 分块处理大 JSONasync function processLargeJSON(file, chunkSize = 1024 * 1024) &#123;    const reader = new FileReader();        return new Promise((resolve, reject) =&gt; &#123;        let offset = 0;        const chunks = [];                reader.onload = (e) =&gt; &#123;            chunks.push(e.target.result);            offset += chunkSize;                        if (offset &lt; file.size) &#123;                readNextChunk();            &#125; else &#123;                // 合并所有块                const fullText = chunks.join(&#x27;&#x27;);                resolve(JSON.parse(fullText));            &#125;        &#125;;                reader.onerror = reject;                function readNextChunk() &#123;            const blob = file.slice(offset, offset + chunkSize);            reader.readAsText(blob);        &#125;                readNextChunk();    &#125;);&#125;// 流式解析大 JSON（简化版）function* parseJSONLines(text) &#123;    const lines = text.split(&#x27;\n&#x27;);        for (const line of lines) &#123;        if (line.trim()) &#123;            yield JSON.parse(line);        &#125;    &#125;&#125;

4. 错误处理4.1 统一错误处理class APIError extends Error &#123;    constructor(message, status, code) &#123;        super(message);        this.name = &#x27;APIError&#x27;;        this.status = status;        this.code = code;    &#125;&#125;async function handleRequest(promise) &#123;    try &#123;        const response = await promise;        return &#123; success: true, data: response &#125;;    &#125; catch (error) &#123;        console.error(&#x27;请求错误:&#x27;, error);                if (error instanceof APIError) &#123;            return &#123;                 success: false,                 error: &#123;                    message: error.message,                    code: error.code                &#125;            &#125;;        &#125;                return &#123;             success: false,             error: &#123;                message: &#x27;网络错误，请稍后重试&#x27;,                code: &#x27;NETWORK_ERROR&#x27;            &#125;        &#125;;    &#125;&#125;// 使用const result = await handleRequest(fetch(&#x27;/api/users&#x27;));if (result.success) &#123;    console.log(&#x27;数据:&#x27;, result.data);&#125; else &#123;    console.error(&#x27;错误:&#x27;, result.error.message);&#125;

4.2 重试机制async function fetchWithRetry(url, options = &#123;&#125;, maxRetries = 3) &#123;    for (let i = 0; i &lt; maxRetries; i++) &#123;        try &#123;            const response = await fetch(url, options);                        if (!response.ok &amp;&amp; response.status &gt;= 500) &#123;                throw new Error(&#x27;服务器错误&#x27;);            &#125;                        return response;        &#125; catch (error) &#123;            if (i === maxRetries - 1) throw error;                        // 指数退避            const delay = Math.pow(2, i) * 1000;            console.log(`等待 $&#123;delay&#125;ms 后重试...`);            await new Promise(resolve =&gt; setTimeout(resolve, delay));        &#125;    &#125;&#125;

5. 最佳实践
使用 Fetch API：现代浏览器的原生支持，比 XMLHttpRequest 更强大
合理设置超时：避免请求无限等待
做好错误处理：区分网络错误和业务错误
使用缓存：减少重复请求，提升性能
请求取消：页面切换时取消不必要的请求
数据验证：接收数据前进行格式验证
安全考虑：敏感数据使用 HTTPS 传输

6. 总结本文详细介绍了 Ajax 和 JSON 的使用方法：

Ajax：XMLHttpRequest、Fetch API、请求超时、进度监控
JSON：语法规则、解析序列化、深拷贝、数据验证
实战技巧：请求封装、缓存、分页、数据转换
错误处理：统一错误处理、重试机制

掌握这些技术后，你就可以更加高效地进行 Web 数据交互开发了。

Cocos Creator 是一款面向中小型开发者的国产游戏引擎，采用 TypeScript&#x2F;JavaScript 作为开发语言，支持一键发布到 Web、iOS、Android、HarmonyOS 等多平台。本文将带领你快速上手 Cocos Creator。


进阶开发的核心技能本文是《Cocos Creator 入门指南》的进阶篇，将深入讲解物理系统、动画系统、性能优化等高级内容，帮助你构建更复杂的游戏项目。
1. 物理系统1.1 刚体与碰撞体Cocos Creator 内置了 Box2D 物理引擎，支持刚体、碰撞体等物理组件。
import &#123; _decorator, Component, RigidBody, BoxCollider &#125; from &#x27;cc&#x27;;const &#123; ccclass, property &#125; = _decorator;@ccclass(&#x27;PhysicsPlayer&#x27;)export class PhysicsPlayer extends Component &#123;    @property(RigidBody)    rigidBody: RigidBody = null;    @property    jumpForce: number = 500;    start() &#123;        // 启用物理        this.rigidBody.enabled = true;    &#125;    jump() &#123;        // 施加向上的力        this.rigidBody.applyForceToCenter(cc.v3(0, this.jumpForce, 0));    &#125;    // 碰撞回调    onBeginContact(selfCollider: BoxCollider, otherCollider: BoxCollider, contact: any) &#123;        console.log(&#x27;碰撞开始&#x27;);    &#125;&#125;

1.2 物理类型


类型
说明
