1.3 碰撞检测// 触发器检测onBeginContact(selfCollider: BoxCollider, otherCollider: BoxCollider, contact: any) &#123;    if (otherCollider.group === 1) &#123; // 收集金币        this.collectCoin(otherCollider.node);    &#125;&#125;// 射线检测update() &#123;    const origin = this.node.position;    const direction = cc.v3(0, -1, 0);    const result = PhysicsSystem.instance.raycast(origin, direction, 1);        if (result.length &gt; 0) &#123;        console.log(&#x27;检测到物体:&#x27;, result[0].collider.node.name);    &#125;&#125;

2. 动画系统2.1 骨骼动画Cocos Creator 支持 Spine 和 DragonBones 骨骼动画。
import &#123; _decorator, Component, Skeleton &#125; from &#x27;cc&#x27;;const &#123; ccclass, property &#125; = _decorator;@ccclass(&#x27;CharacterAnim&#x27;)export class CharacterAnim extends Component &#123;    @property(Skeleton)    skeleton: Skeleton = null;    playAnim(animName: string, loop: boolean = true) &#123;        this.skeleton.setAnimation(0, animName, loop);    &#125;    // 动画事件    setAnimEvent() &#123;        const track = this.skeleton.getAnimationState(0);        track.setEventListener((entry: any, event: any) =&gt; &#123;            console.log(&#x27;动画事件:&#x27;, event.data.name);        &#125;);    &#125;&#125;

2.2 动画状态机import &#123; _decorator, Component, Animation, AnimationState &#125; from &#x27;cc&#x27;;@ccclass(&#x27;AnimController&#x27;)export class AnimController extends Component &#123;    private anim: Animation = null;    private stateMap: Map&lt;string, AnimationState&gt; = new Map();    onLoad() &#123;        this.anim = this.node.getComponent(Animation)!;    &#125;    changeState(stateName: string) &#123;        // 停止当前动画        this.anim.stop();                // 播放新动画        const state = this.anim.play(stateName);        this.stateMap.set(stateName, state);    &#125;    // 带过渡的切换    crossFade(stateName: string, duration: number = 0.3) &#123;        this.anim.crossFade(stateName, duration);    &#125;&#125;

2.3 粒子系统import &#123; _decorator, Component, ParticleSystem &#125; from &#x27;cc&#x27;;@ccclass(&#x27;VFXManager&#x27;)export class VFXManager extends Component &#123;    @property(ParticleSystem)    explosionFX: ParticleSystem = null;    playExplosion(position: cc.Vec3) &#123;        this.explosionFX.node.setPosition(position);        this.explosionFX.play();                // 自动停止        this.explosionFX.stop();        setTimeout(() =&gt; &#123;            this.explosionFX.node.destroy();        &#125;, 2000);    &#125;&#125;

