一、高级动画系统1.1 骨骼动画骨骼动画是游戏开发中最重要的动画技术之一，相比帧动画更省内存且效果更流畅。
import Skeleton from &#x27;laya/display/Skeleton&#x27;;// 创建骨骼动画let skeleton = new Skeleton();// 加载骨架数据skeleton.load(&#x27;res/anim/hero.sk&#x27;);// 播放动画skeleton.play(&#x27;run&#x27;, true);// 混合多个动画skeleton.mix(&#x27;run&#x27;, &#x27;attack&#x27;, 0.5);  // 50%混合// 动画事件skeleton.on(Skeleton.Event.LOOP_COMPLETE, this, () =&gt; &#123;    console.log(&#x27;动画循环完成&#x27;);&#125;);skeleton.on(Skeleton.Event.END, this, () =&gt; &#123;    console.log(&#x27;动画播放结束&#x27;);&#125;);

