二、复杂UI架构2.1 UI层级管理// UI层级常量enum UILevel &#123;    BACKGROUND = 0,    GAME = 100,    DIALOG = 200,    TIP = 300,    LOADING = 400,    MAX = 1000&#125;// 层级管理器class UIManager &#123;    private static instance: UIManager;    private uiLayer: Map&lt;string, View&gt; = new Map();        static getInstance(): UIManager &#123;        if (!UIManager.instance) &#123;            UIManager.instance = new UIManager();        &#125;        return UIManager.instance;    &#125;        showUI(view: View, level: number = UILevel.DIALOG): void &#123;        view.zOrder = level;        Laya.stage.addChild(view);        this.uiLayer.set(view.name, view);    &#125;        closeUI(name: string): void &#123;        let view = this.uiLayer.get(name);        if (view) &#123;            view.destroy();            this.uiLayer.delete(name);        &#125;    &#125;&#125;

2.2 UI适配策略class UIAdapter &#123;    // 基准设计分辨率    static readonly BASE_WIDTH = 750;    static readonly BASE_HEIGHT = 1334;        // 计算缩放比例    static getScale(): number &#123;        let scaleX = Laya.stage.width / this.BASE_WIDTH;        let scaleY = Laya.stage.height / this.BASE_HEIGHT;        return Math.min(scaleX, scaleY);    &#125;        // 适配容器    static adaptContainer(container: Sprite): void &#123;        let scale = this.getScale();        container.scale(scale, scale);        container.x = (Laya.stage.width - container.width * scale) / 2;        container.y = (Laya.stage.height - container.height * scale) / 2;    &#125;&#125;

