import Pool from &#x27;laya/utils/Pool&#x27;;// 创建子弹对象池class BulletPool &#123;    private static pool: any = &#123;&#125;;        // 获取对象    static getBullet(): Bullet &#123;        let bullet = Pool.getItemByClass(&#x27;bullet&#x27;, Bullet);        bullet.init();        return bullet;    &#125;        // 回收对象    static recoverBullet(bullet: Bullet): void &#123;        bullet.reset();        Pool.recover(&#x27;bullet&#x27;, bullet);    &#125;&#125;// 使用示例let bullet = BulletPool.getBullet();// 使用完毕BulletPool.recoverBullet(bullet);

