二、开发环境搭建2.1 安装LayaAir CLI# 全局安装LayaAir CLInpm install -g layaair-cli# 创建3D项目layair create My3DGame --type 3d# 进入项目目录cd My3DGame# 安装依赖npm install# 编译项目npm run build# 开启开发服务器npm run dev

2.2 项目结构My3DGame/├── src/│   ├── Main.ts              # 入口文件│   ├── GameConfig.ts        # 游戏配置│   ├── scenes/              # 场景目录│   │   └── GameScene.ts│   └── scripts/             # 脚本目录├── assets/                  # 资源目录│   ├── models/              # 3D模型│   ├── textures/            # 纹理贴图│   └── scenes/              # 场景文件├── bin/                     # 编译输出目录├── layaair.config           # 项目配置└── package.json


三、TypeScript基础Laya3D推荐使用TypeScript进行开发。
3.1 变量与类型// 基础类型let playerName: string = &#x27;Hero&#x27;;let level: number = 1;let health: number = 100.5;let isAlive: boolean = true;// 3D向量import Vector3 from &#x27;laya/d3/math/Vector3&#x27;;let position: Vector3 = new Vector3(0, 0, 0);let direction: Vector3 = new Vector3(1, 0, 0);// 数组let skills: string[] = [&#x27;火球术&#x27;, &#x27;冰冻术&#x27;];let vertices: Float32Array = new Float32Array(1000);

3.2 类与继承import Sprite3D from &#x27;laya/d3/core/Sprite3D&#x27;;class Character extends Sprite3D &#123;    hp: number = 100;    speed: number = 5;        constructor(name: string) &#123;        super(name);    &#125;        move(direction: Vector3, delta: number): void &#123;        let pos = this.transform.position;        Vector3.add(pos, direction, pos);        this.transform.position = pos;    &#125;        takeDamage(damage: number): void &#123;        this.hp -= damage;        if (this.hp &lt;= 0) &#123;            this.die();        &#125;    &#125;        private die(): void &#123;        this.destroy();    &#125;&#125;


四、Laya3D核心概念4.1 初始化3D引擎import Laya from &#x27;laya&#x27;;import Config from &#x27;laya/Config3D&#x27;;class Main &#123;    constructor() &#123;        // 初始化3D引擎        Laya3D.init(0, 0, true, Config3D.default TransparentBlack);                // 获取舞台        let stage = Laya.stage;                // 设置屏幕适配        stage.scaleMode = Laya.Stage.SCALE_FULL;        stage.screenMode = Laya.Stage.SCREEN_NONE;                // 加载场景        this.loadScene();    &#125;        private loadScene(): void &#123;        // 创建场景        let scene = Laya.Scene3D.load(&#x27;res/scene/MainScene.ls&#x27;);        Laya.stage.addChild(scene);    &#125;&#125;new Main();

4.2 场景 Scene3Dimport Scene3D from &#x27;laya/d3/core/Scene3D&#x27;;import DirectionLight from &#x27;laya/d3/core light/DirectionLight&#x27;;import Vector3 from &#x27;laya/d3/math/Vector3&#x27;;// 创建场景let scene = new Scene3D();// 添加方向光let light = new DirectionLight();light.direction = new Vector3(-1, -1, -1);light.intensity = 1.0;scene.addChild(light);// 添加环境光scene.ambientColor = new Vector3(0.5, 0.5, 0.5);// 添加雾效果scene.fogColor = new Vector3(0.7, 0.7, 0.7);scene.fogStart = 50;scene.fogRange = 200;

4.3 摄像机 Cameraimport Camera from &#x27;laya/d3/core/Camera&#x27;;import Vector3 from &#x27;laya/d3/math/Vector3&#x27;;// 创建摄像机let camera = new Camera();camera.transform.position = new Vector3(0, 10, 20);camera.transform.lookAt(new Vector3(0, 0, 0));// 设置视野角度camera.fieldOfView = 60;// 设置近远裁剪面camera.nearPlane = 0.1;camera.farPlane = 1000;// 添加到场景scene.addChild(camera);// 获取屏幕坐标对应的3D射线let ray = camera.screenPointToRay(screenX, screenY);


五、3D对象与变换5.1 创建3D对象import Sprite3D from &#x27;laya/d3/core/Sprite3D&#x27;;import MeshSprite3D from &#x27;laya/d3/core/MeshSprite3D&#x27;;import PrimitiveMesh from &#x27;laya/d3/resource/models/PrimitiveMesh&#x27;;// 创建空对象let emptyNode = new Sprite3D(&#x27;Empty&#x27;);scene.addChild(emptyNode);// 创建立方体let box = MeshSprite3D.create(PrimitiveMesh.createBox(1, 1, 1));box.transform.position = new Vector3(0, 0, 0);scene.addChild(box);// 创建球体let sphere = MeshSprite3D.create(PrimitiveMesh.createSphere(1, 16, 16));sphere.transform.position = new Vector3(2, 0, 0);scene.addChild(sphere);// 创建圆柱体let cylinder = MeshSprite3D.create(PrimitiveMesh.createCylinder(0.5, 2, 16));scene.addChild(cylinder);

5.2 变换Transformimport Transform3D from &#x27;laya/d3/core/Transform3D&#x27;;import Vector3 from &#x27;laya/d3/math/Vector3&#x27;;import Quaternion from &#x27;laya/d3/math/Quaternion&#x27;;// 设置位置object.transform.position = new Vector3(x, y, z);// 设置旋转（欧拉角）object.transform.rotationEuler = new Vector3(45, 0, 0);// 设置旋转（四元数）object.transform.rotation = new Quaternion(0, 0, 0, 1);// 设置缩放object.transform.scale = new Vector3(1, 1, 1);// 平移object.transform.translate(new Vector3(0, 1, 0));// 旋转object.transform.rotate(new Vector3(0, 90, 0), true);// 缩放object.transform.scale(new Vector3(2, 2, 2));// 获取世界变换let worldMatrix = object.transform.worldMatrix;


六、材质与渲染6.1 创建材质import BlinnPhongMaterial from &#x27;laya/d3/core/material/BlinnPhongMaterial&#x27;;import Texture2D from &#x27;laya/resource/Texture2D&#x27;;// 创建Blinn-Phong材质let material = new BlinnPhongMaterial();// 设置漫反射颜色material.albedoColor = new Vector3(1, 0, 0);// 加载纹理let texture = Texture2D.load(&#x27;res/textures/wood.png&#x27;);material.albedoTexture = texture;// 设置高光material.specularColor = new Vector3(1, 1, 1);material.shininess = 32;// 应用材质到模型model.meshRender.material = material;

6.2 PBR材质import PBRMaterial from &#x27;laya/d3/core/material/PBRMaterial&#x27;;// 创建PBR材质let pbrMaterial = new PBRMaterial();// 设置基础颜色pbrMaterial.albedoColor = new Vector3(0.8, 0.2, 0.2);// 设置金属度（0=非金属，1=金属）pbrMaterial.metallic = 0.8;// 设置粗糙度（0=光滑，1=粗糙）pbrMaterial.roughness = 0.3;// 加载环境贴图pbrMaterial.envTexture = skyboxTexture;// 应用材质model.meshRender.material = pbrMaterial;

6.3 透明材质// 设置透明material.transparency = 0.5;  // 0-1，1完全透明// 设置混合模式material.blendMode = Laya.RenderableProperty3D.BLEND_ALPHA;// 开启深度写入（解决透明排序问题）material.depthWrite = false;


七、灯光系统7.1 方向光 DirectionLightimport DirectionLight from &#x27;laya/d3/core/light/DirectionLight&#x27;;import Vector3 from &#x27;laya/d3/math/Vector3&#x27;;let dirLight = new DirectionLight();dirLight.direction = new Vector3(-1, -2, -1);dirLight.intensity = 1.0;dirLight.color = new Vector3(1, 1, 1);scene.addChild(dirLight);// 开启阴影dirLight.shadow = true;dirLight.shadowDistance = 50;dirLight.shadowResolution = 2048;

7.2 点光源 PointLightimport PointLight from &#x27;laya/d3/core/light/PointLight&#x27;;let pointLight = new PointLight();pointLight.transform.position = new Vector3(0, 5, 0);pointLight.intensity = 1.0;pointLight.range = 20;  // 照射范围scene.addChild(pointLight);

7.3 聚光灯 SpotLightimport SpotLight from &#x27;laya/d3/core/light/SpotLight&#x27;;let spotLight = new SpotLight();spotLight.transform.position = new Vector3(0, 10, 0);spotLight.direction = new Vector3(0, -1, 0);spotLight.intensity = 2.0;spotLight.spotAngle = 45;   // 聚光角度spotLight.range = 30;       // 照射范围scene.addChild(spotLight);


八、摄像机控制8.1 简单摄像机跟随import Camera from &#x27;laya/d3/core/Camera&#x27;;import Vector3 from &#x27;laya/d3/math/Vector3&#x27;;class CameraFollow &#123;    private camera: Camera;    private target: Sprite3D;    private offset: Vector3 = new Vector3(0, 5, -10);        constructor(camera: Camera, target: Sprite3D) &#123;        this.camera = camera;        this.target = target;    &#125;        update(): void &#123;        if (!this.target) return;                let targetPos = this.target.transform.position;        let newPos = new Vector3();        Vector3.add(targetPos, this.offset, newPos);                // 平滑移动        Vector3.lerp(this.camera.transform.position, newPos, 0.1, newPos);        this.camera.transform.position = newPos;                // 看向目标        this.camera.transform.lookAt(targetPos);    &#125;&#125;

8.2 自由视角控制import CameraController from &#x27;laya/d3/component/CameraController&#x27;;let camera = scene.getChildByName(&#x27;MainCamera&#x27;) as Camera;// 添加相机控制器let controller = camera.addComponent(CameraController) as CameraController;// 配置参数controller.distance = 10;controller.minDistance = 2;controller.maxDistance = 50;controller.rotationSpeed = 0.005;controller.panSpeed = 0.5;


九、动画系统9.1 骨骼动画import Animator from &#x27;laya/d3/component/Animator&#x27;;import AnimationClip from &#x27;laya/d3/resource/models/AnimationClip&#x27;;// 加载带动画的模型let hero = Sprite3D.load(&#x27;res/models/hero.lh&#x27;);// 获取动画组件let animator = hero.getComponent(Animator) as Animator;// 播放动画animator.play(&#x27;Run&#x27;);// 混合动画animator.crossFade(&#x27;Run&#x27;, 0.3);// 播放指定片段animator.play(&#x27;Attack&#x27;, 0, 1.0, true);  // 从0帧到1.0（结尾），循环播放// 停止动画animator.stop();

9.2 动画事件animator.on(Laya.Event.COMPLETE, this, () =&gt; &#123;    console.log(&#x27;动画播放完成&#x27;);&#125;);// 监听特定帧animator.on(&#x27;attackHit&#x27;, this, () =&gt; &#123;    // 触发攻击伤害判定    this.checkAttackHit();&#125;);

9.3 程序化动画import Tween from &#x27;laya/d3/animator/KeyframeUtils&#x27;;// 使用缓动动画Laya.Tween.to(object.transform.position, &#123;    x: 10,    y: 5,    z: 0&#125;, 1000, Laya.Ease.quadOut);// 每帧更新Laya.timer.frameLoop(1, this, this.update);private update(): void &#123;    this.object.transform.rotate(new Vector3(0, 1, 0), true);&#125;


十、碰撞检测10.1 碰撞器组件import PhysicsCollider from &#x27;laya/d3/physics/PhysicsCollider&#x27;;import BoxColliderShape from &#x27;laya/d3/physics/shape/BoxColliderShape&#x27;;import SphereColliderShape from &#x27;laya/d3/physics/shape/SphereColliderShape&#x27;;// 添加碰撞器let collider = object.addComponent(PhysicsCollider) as PhysicsCollider;// 添加盒子碰撞体let boxShape = new BoxColliderShape(1, 1, 1);collider.addShape(boxShape);// 添加球体碰撞体let sphereShape = new SphereColliderShape(0.5);collider.addShape(sphereShape);// 设置碰撞组collider.group = 1;  // 自己的组collider.canCollideWith = 2;  // 可以碰撞的组

10.2 射线检测import Ray from &#x27;laya/d3/math/Ray&#x27;;import Vector3 from &#x27;laya/d3/math/Vector3&#x27;;// 创建射线let ray = new Ray(new Vector3(0, 0, 0), new Vector3(0, -1, 0));// 检测碰撞let hitResult = scene.physicsManager.rayCast(ray, 100);// 检测所有碰撞let hitResults = scene.physicsManager.rayCastAll(ray, 100);if (hitResults.length &gt; 0) &#123;    let firstHit = hitResults[0];    console.log(&#x27;击中物体:&#x27;, firstHit.collider.owner.name);&#125;

10.3 触发器// 设置为触发器collider.isTrigger = true;// 监听触发事件collider.on(Laya.Event.TRIGGER_ENTER, this, (other: PhysicsCollider) =&gt; &#123;    console.log(&#x27;进入触发器:&#x27;, other.owner.name);&#125;);collider.on(Laya.Event.TRIGGER_STAY, this, (other: PhysicsCollider) =&gt; &#123;    console.log(&#x27;停留在触发器&#x27;);&#125;);collider.on(Laya.Event.TRIGGER_EXIT, this, (other: PhysicsCollider) =&gt; &#123;    console.log(&#x27;离开触发器:&#x27;, other.owner.name);&#125;);


十一、物理引擎11.1 刚体组件import Rigidbody3D from &#x27;laya/d3/physics/Rigidbody3D&#x27;;// 添加刚体let rigidbody = object.addComponent(Rigidbody3D) as Rigidbody3D;// 设置质量rigidbody.mass = 10;// 设置摩擦力rigidbody.friction = 0.5;// 设置弹性rigidbody.restitution = 0.3;// 设置为运动学刚体（不受物理影响，由代码控制）rigidbody.isKinematic = true;// 应用力rigidbody.applyForce(new Vector3(0, 100, 0));// 应用冲量rigidbody.applyImpulse(new Vector3(0, 50, 0));// 设置速度rigidbody.linearVelocity = new Vector3(0, 0, 10);// 设置角速度rigidbody.angularVelocity = new Vector3(0, 10, 0);

11.2 角色控制器import CharacterController from &#x27;laya/d3/physics/CharacterController&#x27;;// 添加角色控制器let characterController = object.addComponent(CharacterController) as CharacterController;// 设置步高characterController.stepHeight = 0.5;// 设置爬坡角度characterController.slopeLimit = 45;// 移动characterController.move(new Vector3(0, 0, 1), 0.1);// 跳跃characterController.jump(new Vector3(0, 10, 0));


十二、资源管理12.1 加载3D模型import Sprite3D from &#x27;laya/d3/core/Sprite3D&#x27;;// 加载lh文件（预制体）Sprite3D.load(&#x27;res/models/player.lh&#x27;, Laya.Handler.create(this, (sprite) =&gt; &#123;    scene.addChild(sprite);&#125;));// 加载FBX/OBJ（需要转换）// 先使用LayaAir Converter转换格式Sprite3D.load(&#x27;res/models/mesh.lm&#x27;, Laya.Handler.create(this, (sprite) =&gt; &#123;    scene.addChild(sprite);&#125;));

12.2 加载纹理import Texture2D from &#x27;laya/resource/Texture2D&#x27;;Texture2D.load(&#x27;res/textures/wood.png&#x27;, Laya.Handler.create(this, (texture) =&gt; &#123;    material.albedoTexture = texture;&#125;));

12.3 加载场景import Scene3D from &#x27;laya/d3/core/Scene3D&#x27;;// 加载场景Scene3D.load(&#x27;res/scene/MainScene.ls&#x27;, Laya.Handler.create(this, (scene) =&gt; &#123;    Laya.stage.addChild(scene);&#125;));


十三、UI与3D交互13.1 3D物体上的UIimport WorldSpaceCanvas from &#x27;laya/d3/core/WorldSpaceCanvas&#x27;;// 创建世界空间UIlet worldUI = scene.addChild(new WorldSpaceCanvas()) as WorldSpaceCanvas;// 设置位置（在3D空间中）worldUI.transform.position = new Vector3(0, 2, 0);// 设置大小worldUI.width = 500;worldUI.height = 300;

13.2 点击3D物体// 在Camera上添加脚本处理点击import Camera from &#x27;laya/d3/core/Camera&#x27;;let camera = scene.getChildByName(&#x27;MainCamera&#x27;) as Camera;camera.enableMouse = true;camera.on(Laya.Event.MOUSE_DOWN, this, (e: MouseEvent) =&gt; &#123;    let ray = camera.screenPointToRay(e.mouseX, e.mouseY);    let hitResult = scene.physicsManager.rayCast(ray, 100);        if (hitResult) &#123;        console.log(&#x27;点击了:&#x27;, hitResult.collider.owner.name);    &#125;&#125;);


十四、性能优化14.1 渲染优化// 开启多线程渲染Config3D.enableMultithread = true;// 设置最大面数Config3D.maxLightCount = 16;// 减少实时阴影light.shadow = false;// 使用遮挡剔除scene.enableOctree = true;scene.octreeOptions = &#123; minSize: 64, pathTracking: 0.5 &#125;;

14.2 对象池import Pool from &#x27;laya/utils/Pool&#x27;;// 创建对象池let pool = Pool.create(&#x27;bullet&#x27;);// 获取对象let bullet = pool.getItemByClass(&#x27;bullet&#x27;, Sprite3D);// 回收对象pool.recover(&#x27;bullet&#x27;, bullet);


十五、学习路线建议阶段一：环境搭建与基础（1周）
