六、高级摄像机技术6.1 摄像机跟随平滑class SmoothFollow &#123;    private camera: Camera;    private target: Sprite3D;    private smoothSpeed: number = 0.1;    private offset: Vector3 = new Vector3(0, 5, -10);        constructor(camera: Camera, target: Sprite3D) &#123;        this.camera = camera;        this.target = target;    &#125;        update(deltaTime: number): void &#123;        if (!this.target) return;                // 计算目标位置        let targetPos = this.target.transform.position.clone();        Vector3.add(targetPos, this.offset, targetPos);                // 平滑插值        let currentPos = this.camera.transform.position;        let newPos = new Vector3();        Vector3.lerp(currentPos, targetPos, this.smoothSpeed, newPos);                this.camera.transform.position = newPos;                // 看向目标        this.camera.transform.lookAt(this.target.transform.position);    &#125;&#125;

