七、网络同步进阶7.1 预测与回滚class NetworkPrediction &#123;    private localState: GameState;    private remoteState: GameState;    private pendingInputs: Input[] = [];        // 本地预测    applyInput(input: Input): void &#123;        this.pendingInputs.push(input);        this.localState = this.localState.apply(input);    &#125;        // 服务器校正    onServerUpdate(serverState: GameState): void &#123;        // 比较本地和服务器状态        if (this.checkMismatch(this.localState, serverState)) &#123;            // 差异过大，回滚并重放            this.rollback(serverState);        &#125;                this.remoteState = serverState;    &#125;        private rollback(serverState: GameState): void &#123;        // 回滚到服务器状态        this.localState = serverState.clone();                // 重放所有pending的输入        for (let input of this.pendingInputs) &#123;            this.localState = this.localState.apply(input);        &#125;                // 重新渲染        this.syncView(this.localState);    &#125;&#125;

7.2 插值同步class InterpolatedSync &#123;    private remoteStates: GameState[] = [];    private bufferSize: number = 3;        // 接收远程状态    onReceiveRemoteState(state: GameState): void &#123;        this.remoteStates.push(state);                // 保持缓冲区大小        if (this.remoteStates.length &gt; this.bufferSize) &#123;            this.remoteStates.shift();        &#125;    &#125;        // 获取插值状态    getInterpolatedState(): GameState &#123;        if (this.remoteStates.length &lt; 2) &#123;            return this.remoteStates[0];        &#125;                // 对前后两帧进行插值        let prev = this.remoteStates[this.remoteStates.length - 2];        let next = this.remoteStates[this.remoteStates.length - 1];        let alpha = (Date.now() - next.timestamp) / (next.timestamp - prev.timestamp);                return this.interpolate(prev, next, alpha);    &#125;&#125;


八、Shader进阶8.1 水面Shader// Vertex Shaderuniform float uTime;varying vec2 vUv;varying vec3 vWorldPos;void main() &#123;    vUv = uv;    vec3 pos = position;        // 波浪效果    pos.y += sin(pos.x * 0.5 + uTime) * 0.2;    pos.y += cos(pos.z * 0.3 + uTime * 0.8) * 0.15;        gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);    vWorldPos = (modelMatrix * vec4(pos, 1.0)).xyz;&#125;// Fragment Shaderuniform sampler2D uNormalMap;uniform vec3 uWaterColor;void main() &#123;    vec3 normal = texture2D(uNormalMap, vUv).rgb;    vec3 viewDir = normalize(cameraPosition - vWorldPos);        // 菲涅尔效果    float fresnel = pow(1.0 - max(dot(viewDir, normal), 0.0), 3.0);        vec3 color = mix(uWaterColor, vec3(1.0), fresnel);        gl_FragColor = vec4(color, 0.8);&#125;

