1.2 空间复杂度空间复杂度表示算法所需内存空间与输入规模的关系。
2. 常见数据结构2.1 数组数组是最基本的数据结构，提供快速的随机访问。
// 数组基本操作class ArrayList &#123;    constructor() &#123;        this.data = [];        this.size = 0;    &#125;    add(element) &#123;        this.data.push(element);        this.size++;    &#125;    get(index) &#123;        return this.data[index];    &#125;    remove(index) &#123;        return this.data.splice(index, 1)[0];    &#125;&#125;

2.2 链表链表是一种线性数据结构，每个节点包含数据和指向下一个节点的指针。
class ListNode &#123;    constructor(val) &#123;        this.val = val;        this.next = null;    &#125;&#125;class LinkedList &#123;    constructor() &#123;        this.head = null;        this.size = 0;    &#125;    addAtHead(val) &#123;        const node = new ListNode(val);        node.next = this.head;        this.head = node;        this.size++;    &#125;    reverse() &#123;        let prev = null;        let curr = this.head;                while (curr) &#123;            const next = curr.next;            curr.next = prev;            prev = curr;            curr = next;        &#125;                this.head = prev;    &#125;&#125;

2.3 栈与队列栈是后进先出（LIFO），队列是先进先出（FIFO）。
// 栈class Stack &#123;    constructor() &#123;        this.items = [];    &#125;    push(e) &#123; this.items.push(e); &#125;    pop() &#123; return this.items.pop(); &#125;    peek() &#123; return this.items[this.items.length - 1]; &#125;&#125;// 队列class Queue &#123;    constructor() &#123;        this.items = [];    &#125;    enqueue(e) &#123; this.items.push(e); &#125;    dequeue() &#123; return this.items.shift(); &#125;&#125;// 有效括号function isValid(s) &#123;    const stack = new Stack();    const map = &#123; &#x27;)&#x27;: &#x27;(&#x27;, &#x27;]&#x27;: &#x27;[&#x27;, &#x27;&#125;&#x27;: &#x27;&#123;&#x27; &#125;;        for (const char of s) &#123;        if (char in map) &#123;            if (stack.pop() !== map[char]) return false;        &#125; else &#123;            stack.push(char);        &#125;    &#125;        return stack.items.length === 0;&#125;

2.4 哈希表哈希表提供快速的插入、删除和查找操作。
class HashMap &#123;    constructor() &#123;        this.map = new Map();    &#125;        set(key, value) &#123;        this.map.set(key, value);    &#125;        get(key) &#123;        return this.map.get(key);    &#125;        has(key) &#123;        return this.map.has(key);    &#125;        delete(key) &#123;        return this.map.delete(key);    &#125;&#125;// 两数之和function twoSum(nums, target) &#123;    const map = new Map();        for (let i = 0; i &lt; nums.length; i++) &#123;        const complement = target - nums[i];        if (map.has(complement)) &#123;            return [map.get(complement), i];        &#125;        map.set(nums[i], i);    &#125;&#125;

2.5 树二叉树是每个节点最多有两个子节点的数据结构。
class TreeNode &#123;    constructor(val) &#123;        this.val = val;        this.left = null;        this.right = null;    &#125;&#125;// 二叉搜索树class BST &#123;    constructor() &#123;        this.root = null;    &#125;    insert(val) &#123;        const node = new TreeNode(val);                if (!this.root) &#123;            this.root = node;            return;        &#125;                let curr = this.root;        while (true) &#123;            if (val &lt; curr.val) &#123;                if (!curr.left) &#123; curr.left = node; break; &#125;                curr = curr.left;            &#125; else &#123;                if (!curr.right) &#123; curr.right = node; break; &#125;                curr = curr.right;            &#125;        &#125;    &#125;    // 层序遍历    levelOrder() &#123;        if (!this.root) return [];        const result = [];        const queue = [this.root];                while (queue.length) &#123;            const level = [];            const len = queue.length;                        for (let i = 0; i &lt; len; i++) &#123;                const node = queue.shift();                level.push(node.val);                if (node.left) queue.push(node.left);                if (node.right) queue.push(node.right);            &#125;            result.push(level);        &#125;        return result;    &#125;&#125;

2.6 图图由顶点和边组成。
class Graph &#123;    constructor() &#123;        this.adjacencyList = new Map();    &#125;    addVertex(v) &#123;        if (!this.adjacencyList.has(v)) &#123;            this.adjacencyList.set(v, []);        &#125;    &#125;    addEdge(v1, v2) &#123;        this.addVertex(v1);        this.addVertex(v2);        this.adjacencyList.get(v1).push(v2);        this.adjacencyList.get(v2).push(v1);    &#125;    // BFS    bfs(start) &#123;        const visited = new Set();        const queue = [start];        const result = [];                while (queue.length) &#123;            const vertex = queue.shift();            if (!visited.has(vertex)) &#123;                visited.add(vertex);                result.push(vertex);                for (const neighbor of this.adjacencyList.get(vertex)) &#123;                    queue.push(neighbor);                &#125;            &#125;        &#125;        return result;    &#125;    // DFS    dfs(start) &#123;        const visited = new Set();        const result = [];                const dfsHelper = (v) =&gt; &#123;            visited.add(v);            result.push(v);            for (const neighbor of this.adjacencyList.get(v)) &#123;                if (!visited.has(neighbor)) dfsHelper(neighbor);            &#125;        &#125;;                dfsHelper(start);        return result;    &#125;&#125;

3. 常见算法3.1 排序算法// 快速排序function quickSort(arr, left = 0, right = arr.length - 1) &#123;    if (left &gt;= right) return;        const pivot = arr[right];    let i = left - 1;        for (let j = left; j &lt; right; j++) &#123;        if (arr[j] &lt;= pivot) &#123;            i++;            [arr[i], arr[j]] = [arr[j], arr[i]];        &#125;    &#125;        [arr[i + 1], arr[right]] = [arr[right], arr[i + 1]];    const pi = i + 1;        quickSort(arr, left, pi - 1);    quickSort(arr, pi + 1, right);    return arr;&#125;// 归并排序function mergeSort(arr) &#123;    if (arr.length &lt;= 1) return arr;        const mid = Math.floor(arr.length / 2);    const left = mergeSort(arr.slice(0, mid));    const right = mergeSort(arr.slice(mid));        return merge(left, right);&#125;function merge(left, right) &#123;    const result = [];    let i = 0, j = 0;        while (i &lt; left.length &amp;&amp; j &lt; right.length) &#123;        if (left[i] &lt;= right[j]) result.push(left[i++]);        else result.push(right[j++]);    &#125;        return result.concat(left.slice(i)).concat(right.slice(j));&#125;

3.2 查找算法// 二分查找function binarySearch(arr, target) &#123;    let left = 0, right = arr.length - 1;        while (left &lt;= right) &#123;        const mid = Math.floor((left + right) / 2);                if (arr[mid] === target) return mid;        else if (arr[mid] &lt; target) left = mid + 1;        else right = mid - 1;    &#125;        return -1;&#125;

3.3 递归与回溯// 全排列function permute(nums) &#123;    const result = [];        const backtrack = (path, used) =&gt; &#123;        if (path.length === nums.length) &#123;            result.push([...path]);            return;        &#125;                for (let i = 0; i &lt; nums.length; i++) &#123;            if (used[i]) continue;            path.push(nums[i]);            used[i] = true;            backtrack(path, used);            path.pop();            used[i] = false;        &#125;    &#125;;        backtrack([], []);    return result;&#125;// 子集function subsets(nums) &#123;    const result = [];        const backtrack = (start, path) =&gt; &#123;        result.push([...path]);                for (let i = start; i &lt; nums.length; i++) &#123;            path.push(nums[i]);            backtrack(i + 1, path);            path.pop();        &#125;    &#125;;        backtrack(0, []);    return result;&#125;

3.4 动态规划// 斐波那契function fibonacci(n) &#123;    if (n &lt;= 1) return n;    const dp = new Array(n + 1).fill(0);    dp[1] = 1;    for (let i = 2; i &lt;= n; i++) &#123;        dp[i] = dp[i - 1] + dp[i - 2];    &#125;    return dp[n];&#125;// 背包问题function knapSack(weights, values, capacity) &#123;    const n = weights.length;    const dp = new Array(n + 1).fill(0).map(() =&gt; new Array(capacity + 1).fill(0));        for (let i = 1; i &lt;= n; i++) &#123;        for (let w = 0; w &lt;= capacity; w++) &#123;            if (weights[i - 1] &lt;= w) &#123;                dp[i][w] = Math.max(dp[i - 1][w], dp[i - 1][w - weights[i - 1]] + values[i - 1]);            &#125; else &#123;                dp[i][w] = dp[i - 1][w];            &#125;        &#125;    &#125;    return dp[n][capacity];&#125;// 最长递增子序列function lis(nums) &#123;    const dp = new Array(nums.length).fill(1);        for (let i = 1; i &lt; nums.length; i++) &#123;        for (let j = 0; j &lt; i; j++) &#123;            if (nums[i] &gt; nums[j]) &#123;                dp[i] = Math.max(dp[i], dp[j] + 1);            &#125;        &#125;    &#125;    return Math.max(...dp);&#125;

3.5 算法技巧// 双指针 - 有序数组去重function removeDuplicates(nums) &#123;    if (nums.length === 0) return 0;    let slow = 0;    for (let fast = 1; fast &lt; nums.length; fast++) &#123;        if (nums[fast] !== nums[slow]) &#123;            slow++;            nums[slow] = nums[fast];        &#125;    &#125;    return slow + 1;&#125;// 滑动窗口 - 无重复字符最长子串function lengthOfLongestSubstring(s) &#123;    const charIndex = new Map();    let maxLength = 0, left = 0;        for (let right = 0; right &lt; s.length; right++) &#123;        if (charIndex.has(s[right]) &amp;&amp; charIndex.get(s[right]) &gt;= left) &#123;            left = charIndex.get(s[right]) + 1;        &#125;        charIndex.set(s[right], right);        maxLength = Math.max(maxLength, right - left + 1);    &#125;    return maxLength;&#125;// 位运算 - 统计1的个数function countBits(n) &#123;    let count = 0;    while (n) &#123;        n &amp;= n - 1;        count++;    &#125;    return count;&#125;

